const input = $input.first().json;
const data = input.data || {};
const message = data.message || {};
const messageContent = message.content || message.extendedTextMessage || {};
const buttonId = messageContent.buttonResponse?.buttonId || null;
const conversation = (message.conversation || messageContent.text || '').toLowerCase().trim();
const remoteJid = data.key?.remoteJid || null;
let action = null;
let targetPath = null;
let reference = null;

if (buttonId) {
  if (buttonId.startsWith('justify_absence_')) {
    action = 'justify_absence';
    targetPath = 'recepcion-justificacion';
    reference = buttonId.replace('justify_absence_', '');
  } else if (buttonId.startsWith('approve_payment_')) {
    action = 'approve_payment';
    targetPath = 'comprobante-recepcion';
    reference = buttonId.replace('approve_payment_', '');
  } else if (buttonId.startsWith('reject_payment_')) {
    action = 'reject_payment';
    targetPath = 'comprobante-recepcion';
    reference = buttonId.replace('reject_payment_', '');
  } else if (buttonId.startsWith('request_bank_details_')) {
    action = 'request_bank_details';
    targetPath = 'payment-events';
    reference = buttonId.replace('request_bank_details_', '');
  } else if (buttonId.startsWith('authorize_yes_')) {
    action = 'authorize_yes';
    targetPath = 'respuesta-autorizacion';
    reference = buttonId.replace('authorize_yes_', '');
  } else if (buttonId.startsWith('authorize_no_')) {
    action = 'authorize_no';
    targetPath = 'respuesta-autorizacion';
    reference = buttonId.replace('authorize_no_', '');
  } else if (/^\d+$/.test(buttonId)) {
    action = 'confirm_notification_read';
    targetPath = 'confirmacion-lectura';
    reference = buttonId;
  }
} else if (conversation.includes('certificado')) {
  action = 'request_certificate';
  targetPath = 'solicitud-certificado';
} else if (conversation.includes('portal')) {
  action = 'request_portal_link';
  targetPath = 'solicitud-portal-padre';
} else if (conversation.includes('menu')) {
  action = 'request_menu';
  targetPath = 'buzon-notas-padres';
} else if (conversation.includes('ayuda') || conversation.includes('toki')) {
  action = 'toki_query';
  targetPath = 'toki-webhook';
}

return [{ json: { action, targetPath, reference, remoteJid } }];
